CREATE TABLE IF NOT EXISTS RaceLinks
(
	ID     UUID PRIMARY KEY,
	RaceID UUID NOT NULL REFERENCES Races (ID),
	Name   TEXT NOT NULL,
	Type   TEXT NOT NULL,
	URL    TEXT NOT NULL,
	UNIQUE (RaceID, URL)
);

